const http = require("http");

const PORT = 3000;

const routes = {
  "/api/users": process.env.USER_SERVICE_URL,
  "/api/drivers": process.env.DRIVER_SERVICE_URL,
  "/api/trips": process.env.TRIP_SERVICE_URL,
};

function proxyRequest(targetUrl, res) {
  http.get(targetUrl, (backendRes) => {
    let body = "";

    backendRes.on("data", (chunk) => {
      body += chunk;
    });

    backendRes.on("end", () => {
      res.writeHead(backendRes.statusCode || 200, {
        "Content-Type": "application/json"
      });
      res.end(body);
    });
  }).on("error", (err) => {
    res.writeHead(502, { "Content-Type": "application/json" });
    res.end(JSON.stringify({
      error: "Bad Gateway",
      message: err.message
    }));
  });
}

const server = http.createServer((req, res) => {
  if (req.url === "/" || req.url === "/health") {
    res.writeHead(200, { "Content-Type": "application/json" });
    res.end(JSON.stringify({
      service: "api-gateway",
      status: "running",
      routes: Object.keys(routes)
    }));
    return;
  }

  if (routes[req.url]) {
    proxyRequest(routes[req.url], res);
    return;
  }

  res.writeHead(404, { "Content-Type": "application/json" });
  res.end(JSON.stringify({
    error: "Not Found",
    available_routes: ["/health", "/api/users", "/api/drivers", "/api/trips"]
  }));
});

server.listen(PORT, () => {
  console.log(`api-gateway listening on port ${PORT}`);
});
EOF

